typedef struct BenchArray {
    uint16_t kind, flags;
    uint32_t generation, length;
    TurboJSRegionValue values[8];
} BenchArray;
static int gs(TurboJSRegionValue v,uintptr_t s,void*o){(void)v;(void)s;(void)o;return 0;}
static int ls(TurboJSRegionValue v,uint32_t i,TurboJSRegionValue*out,void*o){(void)v;(void)i;(void)out;(void)o;return 0;}
static int ss(TurboJSRegionValue v,uint32_t i,TurboJSRegionValue x,void*o){(void)v;(void)i;(void)x;(void)o;return 0;}
static int ge(TurboJSRegionValue v,uint16_t k,uint32_t g,uint16_t f,void*o){BenchArray*a=(BenchArray*)(uintptr_t)v;(void)o;return a&&a->kind==k&&a->generation==g&&(a->flags&f)==f;}
static int le(TurboJSRegionValue v,uint32_t i,TurboJSRegionValue*out,void*o){BenchArray*a=(BenchArray*)(uintptr_t)v;(void)o;if(!a||i>=a->length)return 0;*out=a->values[i];return 1;}
static int se(TurboJSRegionValue v,uint32_t i,TurboJSRegionValue x,void*o){BenchArray*a=(BenchArray*)(uintptr_t)v;(void)o;if(!a||i>=a->length)return 0;a->values[i]=x;return 1;}
static int al(TurboJSRegionValue v,uint32_t*out,void*o){BenchArray*a=(BenchArray*)(uintptr_t)v;(void)o;if(!a||!out)return 0;*out=a->length;return 1;}
static int ti(TurboJSRegionValue v,int64_t*out,void*o){(void)o;*out=(int64_t)v;return 1;}
static TurboJSRegionValue fi(int64_t v,void*o){(void)o;return (TurboJSRegionValue)v;}
static uint64_t now_ns(void){return turbojs_monotonic_now_ns();}
static void graph(TurboJSSSAGraph*g){memset(g,0,sizeof(*g));g->entry_block=0;g->block_count=g->block_capacity=1;g->blocks=calloc(1,sizeof(*g->blocks));g->blocks[0].reachable=1;g->blocks[0].value_count=4;g->value_count=g->value_capacity=4;g->values=calloc(4,sizeof(*g->values));g->values[0]=(TurboJSSSAValue){.id=0,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_REFERENCE,.immediate=0};g->values[1]=(TurboJSSSAValue){.id=1,.block=0,.opcode=TURBOJS_SSA_CONSTANT_I64,.type=TURBOJS_SSA_TYPE_INT64,.immediate=2};g->values[2]=(TurboJSSSAValue){.id=2,.block=0,.opcode=TURBOJS_SSA_ELEMENT_LOAD,.type=TURBOJS_SSA_TYPE_REFERENCE,.left=0,.right=1,.element_kind=TURBOJS_ELEMENT_KIND_PACKED_I64,.element_generation=7};g->values[3]=(TurboJSSSAValue){.id=3,.block=0,.opcode=TURBOJS_SSA_RETURN,.type=TURBOJS_SSA_TYPE_REFERENCE,.left=2};}
static void dynamic_graph(TurboJSSSAGraph*g){memset(g,0,sizeof(*g));g->entry_block=0;g->block_count=g->block_capacity=1;g->blocks=calloc(1,sizeof(*g->blocks));g->blocks[0].reachable=1;g->blocks[0].value_count=4;g->value_count=g->value_capacity=4;g->values=calloc(4,sizeof(*g->values));g->values[0]=(TurboJSSSAValue){.id=0,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_REFERENCE,.immediate=0};g->values[1]=(TurboJSSSAValue){.id=1,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_INT32,.immediate=1};g->values[2]=(TurboJSSSAValue){.id=2,.block=0,.opcode=TURBOJS_SSA_ELEMENT_LOAD,.type=TURBOJS_SSA_TYPE_REFERENCE,.left=0,.right=1,.element_kind=TURBOJS_ELEMENT_KIND_PACKED_I64,.element_generation=7};g->values[3]=(TurboJSSSAValue){.id=3,.block=0,.opcode=TURBOJS_SSA_RETURN,.type=TURBOJS_SSA_TYPE_REFERENCE,.left=2};}

static void dynamic_store_graph(TurboJSSSAGraph*g){memset(g,0,sizeof(*g));g->entry_block=0;g->block_count=g->block_capacity=1;g->blocks=calloc(1,sizeof(*g->blocks));g->blocks[0].reachable=1;g->blocks[0].value_count=5;g->value_count=g->value_capacity=5;g->values=calloc(5,sizeof(*g->values));g->values[0]=(TurboJSSSAValue){.id=0,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_REFERENCE,.immediate=0};g->values[1]=(TurboJSSSAValue){.id=1,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_INT32,.immediate=1};g->values[2]=(TurboJSSSAValue){.id=2,.block=0,.opcode=TURBOJS_SSA_ARGUMENT,.type=TURBOJS_SSA_TYPE_INT64,.immediate=2};g->values[3]=(TurboJSSSAValue){.id=3,.block=0,.opcode=TURBOJS_SSA_ELEMENT_STORE,.type=TURBOJS_SSA_TYPE_REFERENCE,.left=0,.right=1,.metadata=2,.element_kind=TURBOJS_ELEMENT_KIND_PACKED_I64,.element_flags=TURBOJS_ELEMENT_FLAG_WRITABLE,.element_generation=7};g->values[4]=(TurboJSSSAValue){.id=4,.block=0,.opcode=TURBOJS_SSA_RETURN,.type=TURBOJS_SSA_TYPE_INT64,.left=2};}
int main(void){TurboJSSSAGraph g;TurboJSRegionNativeFunction *guarded=NULL,*native=NULL;TurboJSIRDiagnostic d={0};TurboJSRegionNativeStats st={0};BenchArray a={1,1,7,4,{10,20,30,40}};TurboJSRegionValue args[2]={(TurboJSRegionValue)(uintptr_t)&a,2},out=0;TurboJSRegionValueOps ops={.guard_shape=gs,.load_own_slot=ls,.store_own_slot=ss,.to_i64=ti,.from_i64=fi,.guard_elements=ge,.load_element=le,.store_element=se,.array_length=al};TurboJSRegionElementLayout layout={.object_pointer_mask=UINT64_MAX,.kind_offset=offsetof(BenchArray,kind),.generation_offset=offsetof(BenchArray,generation),.length_offset=offsetof(BenchArray,length),.element_storage_offset=offsetof(BenchArray,values),.element_stride=8};uint64_t t0,t1;size_t i,n=2000000;volatile uint64_t sink=0;graph(&g);if(TurboJS_RegionNativeCompile(&g,&guarded,&st,&d)!=TURBOJS_IR_OK||TurboJS_RegionNativeCompileWithElementLayout(&g,&layout,&native,&st,&d)!=TURBOJS_IR_OK)return 1;for(i=0;i<10000;i++){TurboJS_RegionNativeInvokeValues(guarded,args,1,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){TurboJS_RegionNativeInvokeValues(guarded,args,1,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("guarded_ns_per_call=%.2f\n",(double)(t1-t0)/n);for(i=0;i<10000;i++){TurboJS_RegionNativeInvokeValues(native,args,1,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){TurboJS_RegionNativeInvokeValues(native,args,1,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("native_ns_per_call=%.2f\n",(double)(t1-t0)/n);TurboJS_RegionNativeFunctionDestroy(guarded);TurboJS_RegionNativeFunctionDestroy(native);TurboJS_SSAGraphDestroy(&g);guarded=NULL;native=NULL;dynamic_graph(&g);if(TurboJS_RegionNativeCompile(&g,&guarded,&st,&d)!=TURBOJS_IR_OK||TurboJS_RegionNativeCompileWithElementLayout(&g,&layout,&native,&st,&d)!=TURBOJS_IR_OK)return 1;for(i=0;i<10000;i++){args[1]=i&3;TurboJS_RegionNativeInvokeValues(guarded,args,2,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){args[1]=i&3;TurboJS_RegionNativeInvokeValues(guarded,args,2,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("dynamic_guarded_ns_per_call=%.2f\n",(double)(t1-t0)/n);for(i=0;i<10000;i++){args[1]=i&3;TurboJS_RegionNativeInvokeValues(native,args,2,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){args[1]=i&3;TurboJS_RegionNativeInvokeValues(native,args,2,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("dynamic_native_ns_per_call=%.2f\n",(double)(t1-t0)/n);TurboJS_RegionNativeFunctionDestroy(guarded);TurboJS_RegionNativeFunctionDestroy(native);TurboJS_SSAGraphDestroy(&g);guarded=NULL;native=NULL;dynamic_store_graph(&g);if(TurboJS_RegionNativeCompile(&g,&guarded,&st,&d)!=TURBOJS_IR_OK||TurboJS_RegionNativeCompileWithElementLayout(&g,&layout,&native,&st,&d)!=TURBOJS_IR_OK)return 1;{TurboJSRegionValue sargs[3]={(TurboJSRegionValue)(uintptr_t)&a,0,0};for(i=0;i<10000;i++){sargs[1]=i&3;sargs[2]=i;TurboJS_RegionNativeInvokeValues(guarded,sargs,3,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){sargs[1]=i&3;sargs[2]=i;TurboJS_RegionNativeInvokeValues(guarded,sargs,3,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("dynamic_store_guarded_ns_per_call=%.2f\n",(double)(t1-t0)/n);for(i=0;i<10000;i++){sargs[1]=i&3;sargs[2]=i;TurboJS_RegionNativeInvokeValues(native,sargs,3,&ops,NULL,&out);sink+=out;}t0=now_ns();for(i=0;i<n;i++){sargs[1]=i&3;sargs[2]=i;TurboJS_RegionNativeInvokeValues(native,sargs,3,&ops,NULL,&out);sink+=out;}t1=now_ns();printf("dynamic_store_native_ns_per_call=%.2f\n",(double)(t1-t0)/n);}printf("sink=%" PRIu64 "\n",(uint64_t)sink);TurboJS_RegionNativeFunctionDestroy(guarded);TurboJS_RegionNativeFunctionDestroy(native);TurboJS_SSAGraphDestroy(&g);return 0;}
